  'exercise.tapCardToHear':  { bg: 'Натиснете картичка за произношение', ar: 'انقر على البطاقة لسماع النطق', fr: 'Appuyez sur une carte pour écouter', en: 'Tap a card to hear pronunciation', fa: 'برای شنیدن تلفظ روی کارت ضربه بزنید', uk: 'Натисніть картку для вимови', ru: 'Нажмите на карточку, чтобы услышать произношение' },
